import shioaji as _sj

_EXPORTS = {
    "Ticks": "Ticks",
    "Snapshot": "Snapshot",
    "KBars": "KBars",
    "Kbars": "KBars",
    "DailyQuotes": "DailyQuotes",
    "CreditEnquire": "CreditEnquire",
    "ShortStockSource": "ShortStockSource",
    "ScannerItem": "ScannerItem",
    "UsageStatus": "UsageOut",
    "UsageOut": "UsageOut",
    "Punish": "Punish",
    "Notice": "Notice",
}

def __getattr__(name):
    if name in _EXPORTS:
        import warnings
        warnings.warn(
            f"shioaji.data.{name} is deprecated, use sj.{_EXPORTS[name]}",
            DeprecationWarning,
            stacklevel=2,
        )
        return getattr(_sj, _EXPORTS[name])
    raise AttributeError(f"module 'shioaji.data' has no attribute {name!r}")
